INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(12, 13, E'# TurnedIn \x2014 Early-Warning Homework Analytics for K-8 Classrooms\n\n## 1. Executive Summary\n\nTurnedIn is a homework completion analytics platform that helps K-8 teachers identify struggling students 2\xe2\x80\x934 weeks earlier than traditional report card cycles. While most homework tracking tools simply record who turned in what, TurnedIn applies trend analysis to surface at-risk students based on patterns: three consecutive misses, completion rate dropping below a threshold, a sudden change after previously being consistent. Teachers get a prioritized action list each Monday morning. Parents receive real-time alerts (not just weekly digests) when their child misses two assignments in a row. TurnedIn is optimized for teachers managing 25\xe2\x80\x9335 students who want actionable intelligence, not just another spreadsheet.\n\n**Year-1 Goals**:\n- 900 active teacher accounts\n- 80% of enrolled teachers report identifying a struggling student earlier than they would have otherwise\n- MRR of $15,500 by month 12\n\n## 2. Market Analysis\n\n| Metric | Data | Source |\n|--------|------|--------|\n| K-8 classroom teachers (US) | ~1.8M | NCES 2023 |\n| Teachers using Google Classroom or similar LMS | ~62% | EdWeek 2023 |\n| % satisfied with LMS homework tracking | ~28% | EdWeek Research |\n| Average time identifying a struggling student | 3\xe2\x80\x936 weeks after pattern starts | Teacher interviews |\n| Early intervention success rate (caught in wk 2 vs wk 6) | 2.4\xd7 higher | What Works Clearinghouse |\n| Teacher-paid classroom tool spending | $479/year avg | DonorsChoose survey 2023 |\n| Parent demand for more frequent academic updates | 71% | NPTA 2023 |\n| TAM (K-8 academic tracking SaaS) | ~$360M/year | NCES \xd7 estimated ARPU |\n| Year-1 SOM | ~$186K | 900 \xd7 $17/mo avg |\n\n## 3. Competitive Landscape\n\n| Product | Analytics Depth | Early-Warning Alerts | Parent Notifications | Price/mo | Weakness |\n|---------|----------------|----------------------|----------------------|----------|----------|\n| Google Classroom | Basic (missing label) | No | No | Free | No trend analysis, no parent alerts |\n| Seesaw | Portfolio focus | No | Messaging only | Free/$10 | Not analytics-oriented |\n| ClassDojo | Behavior points | No | Yes (behavior) | Free | No academic completion tracking |\n| Skyward / PowerSchool | Gradebook | Limited | Yes (grades) | School license | Grades, not assignments; requires IT |\n| Formative | Assessment focus | No | No | $12\xe2\x80\x9325 | Assessment, not homework tracking |\n| **TurnedIn** | **Trend analysis** | **Yes (core)** | **Yes (real-time + digest)** | **$15\xe2\x80\x9319** | **New brand** |\n\n## 4. Target User Personas\n\n### Persona A: Data-Curious 5th Grade Teacher \xe2\x80\x94 Ms. Rachel Kim\n- **Age**: 31, 5th grade, suburban New Jersey, 32 students\n- **Background**: Former data analyst career-switched to teaching; loves dashboards\n- **Pain Points**:\n  1. Google Classroom shows who is \xe2\x80\x9cmissing\xe2\x80\x9d but no trend over time\n  2. She notices patterns but has no easy way to track them without a custom spreadsheet\n  3. By the time she calls parents, the student has been slipping for 4 weeks\n- **Goal**: Get an automatic Monday morning report showing who needs attention this week\n- **WTP**: $15\xe2\x80\x9319/month personal; would advocate for school adoption at $8/teacher\n\n### Persona B: Veteran 3rd Grade Teacher \xe2\x80\x94 Mrs. Barbara Kowalski\n- **Age**: 57, 3rd grade, rural Minnesota, 26 students\n- **Tech Comfort**: Moderate; uses Google Classroom but finds it clunky\n- **Pain Points**:\n  1. Has seen students fall behind for 6+ weeks before parents knew\n  2. Wants to contact parents early but dreads making manual calls for each one\n  3. Needs something simpler than a spreadsheet formula\n- **Goal**: Automated parent notification so she doesn\xe2\x80\x99t have to be the bearer of bad news manually\n- **WTP**: $12\xe2\x80\x9315/month; values simplicity over features\n\n### Persona C: Instructional Coach \xe2\x80\x94 Mr. Leon Foster\n- **Age**: 46, coaches 8 teachers at a Title I middle school in Georgia\n- **Use Case**: Wants aggregate view of homework completion rates across all 8 classrooms to identify systemic issues\n- **WTP**: School budget; advocates for $8/teacher/month school plan (~$768/month for the team)\n\n## 5. Core Features\n\n| Feature | Priority | Description |\n|---------|----------|-------------|\n| Assignment logging (title, due date, subject, weight) | P0 | Teacher creates assignments in 30 seconds |\n| Per-student completion tracking | P0 | Mark complete/incomplete/late; teacher or student entry |\n| Early-warning alert engine | P0 | Flags student when: 3 consecutive misses OR completion rate <60% over 2 weeks |\n| Monday morning action list | P0 | Prioritized list of students needing teacher attention this week |\n| Real-time parent alert (2-miss trigger) | P0 | Auto-SMS/email to parent after 2 consecutive missing assignments |\n| Weekly parent digest | P1 | Sunday email with completion stats, missing items, trend sparkline |\n| Trend sparkline per student | P1 | 8-week rolling completion rate chart |\n| Google Classroom sync | P1 | Import assignments and submission status |\n| Conference report PDF | P1 | Per-student packet for parent-teacher conferences |\n| Multi-class management | P1 | Middle school teachers managing 3\xe2\x80\x934 periods |\n| Grade-level aggregate view | P2 | Instructional coaches see across classrooms |\n| Intervention log | P2 | Teacher notes what action was taken per flagged student |\n\n## 6. Technical Architecture\n\n**Backend**: Node.js 20 + Express 5. PostgreSQL 16 (RDS, encrypted). Redis for alert queuing and session management.\n\n**Alert Engine**: Event-driven microservice. When a completion record is updated, a worker evaluates the student\xe2\x80\x99s rolling window. If threshold crossed, queues parent notification immediately. Deduplicates alerts per student per 24-hour window.\n\n**Frontend**: Next.js 15 + TailwindCSS. Student grid uses virtual scrolling for classes with 35+ students. Trend sparklines rendered with lightweight Recharts.\n\n**Google Classroom Integration**: REST API v1, OAuth 2.0 teacher auth. Incremental sync every 30 minutes. Handles submission status mapping (turned_in, missing, late).\n\n**Communications**: Twilio SMS for real-time alerts; SendGrid for digests. Parent contact info stored encrypted; teachers enter at class setup or import from school roster CSV.\n\n**FERPA**: Student data minimized to first name + last initial + grade. No student-facing accounts for under-13 without parental consent. Annual data purge 14 months after last activity.\n\n## 7. Business Model\n\n| Plan | Price/Month | Students | Features |\n|------|-------------|----------|----------|\n| Solo | $15 | Up to 40 | Core tracking, early-warning alerts, parent digests |\n| Pro | $22 | Up to 120 | + Multi-class, Google Classroom sync, conference reports, parent portal |\n| School | $8/teacher | Unlimited | + Grade-level view, admin dashboard, bulk billing, onboarding support |\n\n**Revenue Projections**:\n- Y1: 900 teachers, avg $17.30/mo = $186K ARR\n- Y2: 3,200 teachers (30% school plans) = $780K ARR\n- Y3: 9,000 teachers = $2.2M ARR\n\n## 8. MVP Roadmap\n\n| Milestone | Timeline | Deliverables |\n|-----------|----------|--------------|\n| M1 | Weeks 1\xe2\x80\x934 | Assignment CRUD, completion marking, student grid, early-warning engine v1 (consecutive miss rule) |\n| M2 | Weeks 5\xe2\x80\x938 | Real-time parent SMS alert, weekly digest email, Monday action list, CSV import |\n| M3 | Weeks 9\xe2\x80\x9312 | Google Classroom sync, parent portal, conference report PDF, trend sparklines |\n| M4 | Weeks 13\xe2\x80\x9316 | Multi-class view, school/admin dashboard, Stripe billing, referral program |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M12 Target |\n|-----|-----------|------------|\n| Active teacher accounts | 120 | 900 |\n| Early-warning alert actions taken by teacher | >65% | >80% |\n| Parent SMS/email open rate | >55% | >62% |\n| MRR | $1,800 | $15,500 |\n| Monthly churn | <8% | <5% |\n| Google Classroom sync adoption | \xe2\x80\x94 | >55% of Pro users |\n| NPS | >50 | >68 |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|------|------------|--------|------------|\n| False-positive alerts alienating parents | Medium | High | Allow teachers to review and approve alerts before sending; add snooze/override controls |\n| FERPA under-13 student data risk | Low | Critical | No student accounts under 13; all data entered by teachers; legal review in M1 |\n| Google Classroom sync breaks on API update | Medium | Medium | Maintain manual entry as primary interface; sync is enhancement, not dependency |\n| Parent SMS opt-out reduces engagement | Medium | Medium | Default to email; SMS requires explicit opt-in; explain value before requesting number |\n| Teacher churn over summer | High | Medium | Annual plan with summer pause; \xe2\x80\x9cnew class setup wizard\xe2\x80\x9d in August drives re-engagement |\n| Gradebook tools (PowerSchool) adding homework tracking | Low | High | Differentiate on parent communication and early-warning UX; school tools are slow to add consumer-quality features |',
 E'[{"step": 1, "action": "Insight framing", "rationale": "Reframed homework tracking as an \x27early warning system\x27 rather than record-keeping. Research shows early intervention is 2.4x more effective, which is a compelling teacher motivation."}, {"step": 2, "action": "Alert design", "rationale": "Deliberated between weekly digest vs. real-time alerts. Decided on both: real-time for the 2-miss trigger (urgency), weekly for normal status updates (less noise)."}, {"step": 3, "action": "Competitive gap analysis", "rationale": "None of the free tools (Google Classroom, Seesaw, ClassDojo) have early-warning analytics. This is the core differentiator."}, {"step": 4, "action": "FERPA design decisions", "rationale": "Chose teacher-entered data model (no student accounts under 13) to sidestep COPPA/FERPA complexity while still capturing needed data."}, {"step": 5, "action": "Pricing validation", "rationale": "Set Solo at $15/mo based on teacher interview data: most pay $10-20/mo for tools they use daily. Pro at $22 for multi-class teachers justified by time savings."}, {"step": 6, "action": "GTM strategy", "rationale": "Primary channel is teacher-to-teacher referral via grade-level teams. School plan discounting at $8/teacher incentivizes team lead advocacy."}]',
 'submitted', 27,
 NOW() - INTERVAL '20 days', NOW() - INTERVAL '20 days', NOW() - INTERVAL '20 days');

