INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(12, 19, E'# HomeBase \x2014 Parent-Integrated Homework Accountability for K-8\n\n## 1. Executive Summary\n\nHomeBase is a homework accountability platform that bridges the gap between classroom and home. Unlike tools that only show teachers what\xe2\x80\x99s missing, HomeBase keeps parents actively informed and creates a shared accountability loop: teacher assigns, student completes (or parent confirms completion at home), teacher verifies. This three-party model is especially powerful in grades K\xe2\x80\x935 where parents are engaged but lack visibility into what is actually due each night. HomeBase reduces the \xe2\x80\x9cI didn\xe2\x80\x99t know there was homework\xe2\x80\x9d excuse while giving teachers a completion dashboard that auto-generates parent reports for conferences and IEP documentation.\n\n**Unique Angle**: HomeBase is the only K-8 homework tool designed for three users\xe2\x80\x94teacher, student, parent\xe2\x80\x94each with a role-appropriate view.\n\n**Year-1 Goals**:\n- 800 active classroom accounts\n- 3-party engagement rate (teacher + at least one parent active) >45%\n- MRR of $13,500 by month 12\n\n## 2. Market Analysis\n\n| Metric | Data | Source |\n|--------|------|--------|\n| K-8 classroom teachers (US) | ~1.8M | NCES 2023 |\n| K-5 teachers (parent engagement most active) | ~1.1M | NCES breakdown |\n| Parents who check homework status daily | 58% of elementary parents | NPTA 2023 |\n| Parents satisfied with current school communication | 34% | PTA national survey |\n| Teachers spending 45+ min/week on parent communication | 61% | WeAreTeachers survey |\n| Average # of parent-teacher communication tools used | 2.8 | Educator survey N=220 |\n| Parents willing to pay a small fee for better communication | 27% | Survey Monkey parent poll |\n| TAM (K-8 family engagement tools) | ~$220M/year | Estimated |\n| Year-1 SOM | ~$162K | 800 teachers \xd7 $17/mo |\n\n## 3. Competitive Landscape\n\n| Product | Teacher View | Parent View | Student View | Price | Weakness |\n|---------|-------------|-------------|--------------|-------|----------|\n| Google Classroom | Strong | None (can see with login) | Yes | Free | No parent-native experience |\n| ClassDojo | Behavior | Yes (behavior) | Limited | Free | Behavior-focused, no homework tracking |\n| Seesaw | Portfolio | Yes | Yes (portfolio) | Free/$10 | Portfolio model, not completion tracking |\n| Remind | None | Messaging | No | Free | Pure messaging, no academic data |\n| Bloomz | Limited | Messaging | No | $8/mo | Communication only |\n| **HomeBase** | **Completion + analytics** | **Live + digest** | **Age-appropriate** | **$15\xe2\x80\x9319/mo** | **New brand** |\n\n## 4. Target User Personas\n\n### Persona A: Engaged Elementary Teacher \xe2\x80\x94 Ms. Theresa Dupont\n- **Age**: 34, 2nd grade, suburban Ohio, 24 students\n- **Current Tools**: Seesaw for portfolios, Remind for messaging, paper agenda books for homework\n- **Pain Points**:\n  1. Three different tools with no single view of homework status\n  2. Parents message her on Remind asking what homework is due; she answers the same question 8 times per night\n  3. When a student misses homework, she can\xe2\x80\x99t tell if the parent knows\n- **Goal**: One tool that tells her who\xe2\x80\x99s done, notifies parents automatically, and stops the nightly Remind questions\n- **WTP**: $15/month; values eliminating after-hours messaging\n\n### Persona B: Involved K-3 Parent \xe2\x80\x94 Marcus and Linda Chen\n- **Ages**: 38, 36; son in 1st grade, suburban California\n- **Pain Points**:\n  1. Son comes home and says \xe2\x80\x9cno homework\xe2\x80\x9d but teacher says he had assignments\n  2. They don\xe2\x80\x99t know what\xe2\x80\x99s due until the night it\xe2\x80\x99s due\n  3. Want to confirm completion without nagging their son every night\n- **Goal**: A simple daily checklist of what was assigned and whether their son marked it done\n- **WTP**: Would use free parent app; their child\xe2\x80\x99s teacher pays for the classroom subscription\n\n### Persona C: Special Education Teacher \xe2\x80\x94 Ms. Alicia Martin\n- **Age**: 41, 4th grade inclusion teacher, New York, 18 students (6 with IEPs)\n- **Pain Points**:\n  1. IEP documentation requires evidence of homework completion patterns\n  2. Parents of students with IEPs demand more frequent updates\n  3. Sharing data with special ed coordinators requires manual exports\n- **Goal**: Automated documentation of completion patterns; easy IEP-ready reports\n- **WTP**: $19\xe2\x80\x9322/month for enhanced reporting\n\n## 5. Core Features\n\n| Feature | Priority | Description |\n|---------|----------|-------------|\n| Teacher assignment creation | P0 | Title, subject, due date, instructions, attachment link |\n| Teacher completion dashboard | P0 | Per-student, per-assignment status (complete/incomplete/parent-confirmed) |\n| Parent daily homework list | P0 | Parent app/email shows today\xe2\x80\x99s assignments; one-tap confirm child completed |\n| Automated parent evening reminder | P0 | 6 PM push notification listing tonight\xe2\x80\x99s assignments |\n| Student checklist view (grades 3\xe2\x80\x938) | P0 | Simple age-appropriate checklist; student marks done |\n| Struggling student flag | P1 | Teacher alert when student misses 3+ in 2 weeks |\n| Weekly teacher summary digest | P1 | Class-wide completion rates, top missing students |\n| Google Classroom import | P1 | Sync assignments; parent/student updates flow back |\n| Conference/IEP report export | P1 | PDF with per-student completion history, trends, annotations |\n| Parent-teacher messaging (in-app) | P2 | Threaded per-assignment conversation |\n| Grade-level view for coordinators | P2 | Admin/coordinator sees aggregate across classrooms |\n\n## 6. Technical Architecture\n\n**Backend**: Go 1.22 + Echo v4. PostgreSQL 16. FERPA-compliant AWS infrastructure.\n\n**Three-User Model**: Teachers have full access. Parent accounts linked to specific student(s) via teacher-issued invite code. Student accounts for grades 3+ (teacher creates, no email required for K-2). Role-based access strictly enforced at API layer.\n\n**Parent App**: React Native (iOS + Android) for the evening notification experience. Push notifications via Firebase Cloud Messaging. Parents can also use mobile web if they prefer not to install an app.\n\n**Evening Notification Engine**: Cron job at 5:45 PM local time per class. Generates per-student homework list. Sends FCM push + SendGrid email backup.\n\n**Google Classroom Sync**: OAuth 2.0 teacher auth. Imports course assignments every 30 minutes. Parent and student completion confirmations stored in HomeBase only (not written back to Classroom).\n\n**FERPA/COPPA**: Student accounts for K-2 created by teacher (no student email required). Parent accounts linked via invite; parental consent implicit in accepting invite. No ads, no data sale, no third-party analytics on student data.\n\n## 7. Business Model\n\n| Plan | Price/Month | Students | Parent App | Features |\n|------|-------------|----------|------------|----------|\n| Starter | $15 | Up to 35 | Yes | Core tracking, parent evening reminders, weekly digest |\n| Pro | $21 | Up to 100 | Yes | + Google Classroom sync, IEP/conference reports, multi-class |\n| School | $9/teacher | Unlimited | Yes | + Coordinator view, admin dashboard, bulk billing, onboarding |\n\n**Free Parent Access**: Parent app and notifications are always free. The teacher pays for the classroom subscription.\n\n**School Upsell**: Target district-level adoption after 5+ teachers in same school are on Starter/Pro; offer school plan at 40% discount to administrator.\n\n## 8. MVP Roadmap\n\n| Milestone | Timeline | Deliverables |\n|-----------|----------|--------------|\n| M1 | Weeks 1\xe2\x80\x934 | Teacher web app (assignment CRUD, completion dashboard), parent invite system, basic student checklist (web) |\n| M2 | Weeks 5\xe2\x80\x938 | Evening push notifications (FCM), parent mobile web, struggling student alerts, weekly teacher digest |\n| M3 | Weeks 9\xe2\x80\x9312 | React Native parent app (iOS + Android), Google Classroom sync, conference report PDF |\n| M4 | Weeks 13\xe2\x80\x9316 | Multi-class, school admin view, Stripe billing, FERPA documentation, App Store submission |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M12 Target |\n|-----|-----------|------------|\n| Active teacher accounts | 100 | 800 |\n| 3-party activation (teacher + parent active) | 35% | 45% |\n| Evening notification open rate | >48% | >58% |\n| MRR | $1,500 | $13,500 |\n| Monthly churn (teachers) | <8% | <5% |\n| Parent app store rating | \xe2\x80\x94 | >4.4 stars |\n| NPS (teachers) | >45 | >62 |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|------|------------|--------|------------|\n| COPPA/FERPA complexity delays launch | Medium | High | Limit student data to teacher-entered fields; no student email for K-2; legal counsel reviews before M1 launch |\n| Parent app adoption lower than expected | High | Medium | Ensure core teacher value (dashboard, alerts) works without parent adoption; parent app is bonus, not requirement |\n| Evening notification fatigue (parents opt out) | Medium | Medium | Make notifications digestible (1 message, clear list); allow frequency preferences |\n| React Native app store approval delays | Medium | Medium | Launch mobile web first (M2); native app enhances but doesn\xe2\x80\x99t block launch |\n| Google Classroom policy changes | Low | Medium | Keep Classroom sync as enhancement; manual entry always available |\n| Teacher switches schools mid-year (data portability) | Low | Low | Export student data to CSV at any time; easy class import for new school year |',
 E'[{"step": 1, "action": "Three-party model design", "rationale": "Most tools serve only teachers. Adding a designed parent experience (not just a read-only portal) creates a stronger accountability loop and differentiates HomeBase."}, {"step": 2, "action": "K-2 vs 3-8 student experience split", "rationale": "K-2 students cannot reliably self-report homework; parent confirmation is the only viable model. Grades 3-8 students can use a checklist. Designed two flows accordingly."}, {"step": 3, "action": "Evening notification timing research", "rationale": "Surveyed 22 parents: 6-7 PM is the peak homework help window. Sending notifications at 6 PM maximizes parent action before the child\xe2\x80\x99s bedtime."}, {"step": 4, "action": "Free parent model decision", "rationale": "Charging parents directly creates friction and splits the buying decision. Teacher pays; parents get free access. This also removes the \x27parents won\x27t pay\x27 objection."}, {"step": 5, "action": "React Native vs web app trade-off", "rationale": "Evening push notifications require a native app for reliable delivery. Decided to ship mobile web first (M2) and native app in M3 to avoid App Store delays blocking early traction."}, {"step": 6, "action": "IEP/special-ed use case", "rationale": "Special ed teachers are a high-value niche: they have a documented need for completion tracking, are accustomed to paying for specialized tools, and advocate within schools."}]',
 'submitted', 35,
 NOW() - INTERVAL '15 days', NOW() - INTERVAL '15 days', NOW() - INTERVAL '15 days');

