INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(14, 14, E'# RenewalRadar \x2014 Policy Renewal Intelligence for Independent Insurance Agents\n\n## 1. Executive Summary\n\nRenewalRadar gives independent insurance agents a 90-day forward view of every policy renewal in their book, combined with automated client outreach sequences and a referral attribution engine. Unlike general-purpose CRMs that require agents to set up workflows from scratch, RenewalRadar ships with insurance-specific sequences pre-configured: the agent imports their book, sets their preferences, and the system begins working on day one. The core insight is that the 30 days before a policy renewal is the highest-stakes window in the agent\xe2\x80\x93client relationship\xe2\x80\x94and most agents are losing that window to manual processes and reactive firefighting.\n\n**Core Differentiator**: RenewalRadar is pre-configured for insurance agents out of the box. No workflow setup, no CRM customization. Import your book on Monday; your first automated renewal sequences go out on Wednesday.\n\n**Year-1 Goals**:\n- 450 active subscriptions\n- Zero-to-first-automated-sequence in <4 hours for average agent\n- MRR of $67,500 by month 12\n\n## 2. Market Analysis\n\n| Metric | Data | Source |\n|--------|------|--------|\n| Independent insurance agents (US) | ~360,000 | IIABA 2023 |\n| Target segment (200\xe2\x80\x93500 clients) | ~108,000 | Estimated |\n| Avg annual commission per client | $180\xe2\x80\x93$350 | Industry benchmarks |\n| Clients lost annually to preventable lapses | 3\xe2\x80\x935% | Agent interview avg |\n| Revenue impact of 3% lapse rate (300-client book) | ~$11,000/year | Calculated |\n| Hours/week on manual renewal tracking | 4.2 hrs avg | Survey N=180 |\n| Agents satisfied with current renewal process | 19% | Same survey |\n| TAM | ~$648M/year | 108,000 \xd7 $500/yr |\n| Year-1 SOM | ~$810K | 450 \xd7 $150/mo |\n\n## 3. Competitive Landscape\n\n| Product | Out-of-Box Insurance Config | Renewal Sequences | Referral Attribution | Ease of Setup | Price/mo |\n|---------|----------------------------|-------------------|----------------------|---------------|----------|\n| AgencyZoom | Yes | Yes | No | Medium | $99\xe2\x80\x93$249 |\n| HawkSoft | Yes (agency ops) | Basic | No | Hard | $200\xe2\x80\x93$400 |\n| Applied Epic | Yes (enterprise) | Yes | No | Very Hard | $300\xe2\x80\x93$600+ |\n| HubSpot | No (generic) | Yes (manual setup) | No | Medium | $50\xe2\x80\x93$450 |\n| NowCerts | Yes | Basic | No | Easy | $79\xe2\x80\x93$159 |\n| **RenewalRadar** | **Yes (pre-configured)** | **Advanced** | **Yes** | **Very Easy** | **$99\xe2\x80\x93$169** |\n\n## 4. Target User Personas\n\n### Persona A: Time-Strapped P&C Agent \xe2\x80\x94 Mike Saunders\n- **Age**: 46, independent P&C agent in suburban Colorado, 310 clients\n- **Current Situation**: Uses an Excel spreadsheet sorted by renewal date; reviews it every Monday morning\n- **Pain Points**:\n  1. His spreadsheet shows renewals but doesn\xe2\x80\x99t remind him\xe2\x80\x94he forgets to check it during busy weeks\n  2. Carriers require 30-day notice to cancel; if he misses the window, the policy lapses automatically\n  3. Spends 4+ hours/week on manual outreach that could be automated\n- **Quote**: \xe2\x80\x9cI need something that works without me having to babysit it.\xe2\x80\x9d\n- **WTP**: $119\xe2\x80\x93$149/month; values zero-setup requirement\n\n### Persona B: Life & Health Agent Building Referral Business \xe2\x80\x94 Nicole Chambers\n- **Age**: 38, independent life + health agent in Florida, 225 clients\n- **Pain Points**:\n  1. Her best referral sources are 8\xe2\x80\x9310 clients who each send 3\xe2\x80\x934 referrals/year; she doesn\xe2\x80\x99t know which they are\n  2. She thanks referrers with a handwritten note\xe2\x80\x94but sometimes months after the referral, when it\xe2\x80\x99s awkward\n  3. Wants to identify cross-sell opportunities (clients with life but no LTD, etc.)\n- **Goal**: Identify and reward her top referrers systematically; grow via referrals instead of cold prospecting\n- **WTP**: $99\xe2\x80\x93$129/month\n\n### Persona C: New Independent Agent \xe2\x80\x94 Chris Morales\n- **Age**: 27, just left a captive carrier 8 months ago, 180 clients, growing fast\n- **Pain Points**:\n  1. Building his book and his systems simultaneously; overwhelmed\n  2. No structured renewal process; relies on memory and calendar alerts\n  3. Knows he should be doing annual reviews but hasn\xe2\x80\x99t systematized it yet\n- **Goal**: A system that establishes professional habits from the start\n- **WTP**: $79\xe2\x80\x9399/month starter\n\n## 5. Core Features\n\n| Feature | Priority | Description |\n|---------|----------|-------------|\n| Policy book import (CSV, carrier export) | P0 | Auto-parse renewal dates, client contact info, policy type; map to standard fields |\n| Pre-configured renewal sequences | P0 | 90/60/30/14-day touchpoints pre-built; agent customizes messaging but not workflow |\n| 90-day renewal pipeline view | P0 | Visual pipeline: policies grouped by renewal month; color-coded urgency |\n| Daily priority queue | P0 | \xe2\x80\x9cDo these 5 things today\xe2\x80\x9d: renewal calls, check-ins, referral follow-ups |\n| Referral attribution engine | P0 | Log referral source at client creation; track referral chain; identify top referrers |\n| Automated referral thank-you sequence | P1 | Trigger thank-you email/SMS to referrer within 24 hrs of new client creation |\n| Annual review scheduler | P1 | Schedule one annual touchpoint per client; auto-generate agenda based on policy mix |\n| Cross-sell opportunity scanner | P1 | Flag single-line clients as candidates for additional coverage |\n| Client note + communication history | P1 | Per-client log with timeline view |\n| Carrier-specific import templates | P2 | One-click import for Nationwide, Progressive, Travelers, Allstate, Liberty Mutual |\n\n## 6. Technical Architecture\n\n**Backend**: Python 3.12 + FastAPI. PostgreSQL 16 (RDS). Celery + Redis for async sequence execution.\n\n**Sequence Engine**: Policy renewal dates trigger Celery beat tasks. Each task: check if action is already completed (idempotent); if not, queue outreach via Twilio/SendGrid; create in-app task for agent review before send (optional approval mode).\n\n**Import Pipeline**: Multi-format CSV parser with field-mapping UI. Fuzzy match on common carrier export column names (e.g., \xe2\x80\x9cPolicy Expiration Date\xe2\x80\x9d, \xe2\x80\x9cExp Date\xe2\x80\x9d, \xe2\x80\x9cRen Date\xe2\x80\x9d). Validation report shows unmatched rows before commit.\n\n**Frontend**: Next.js 15 + TailwindCSS 4. Pipeline view uses a horizontal kanban sorted by renewal month. Daily priority queue is a checkbox-based to-do list with action type icons.\n\n**Referral Graph**: PostgreSQL adjacency list (client_id \xe2\x80\x94 referred_by \xe2\x80\x94 referrer_id). Referral chain visualization up to 3 levels. Top-10 referrers leaderboard updated nightly.\n\n**Security**: SOC 2 Type II in roadmap. Client PII encrypted at rest. Agent data fully isolated. TCPA-compliant SMS: explicit opt-in required before any automated client SMS.\n\n## 7. Business Model\n\n| Plan | Price/Month | Clients | Features |\n|------|-------------|---------|----------|\n| Starter | $99 | Up to 200 | Renewal sequences, pipeline view, daily queue, referral tracking |\n| Pro | $149 | Up to 500 | + Annual review scheduler, cross-sell scanner, communication log, carrier templates |\n| Team | $219 | Unlimited | + Multi-producer, agency pipeline, team leaderboard, white-label sequences |\n\n**Annual billing**: 2 months free (effective 17% discount). Targets sub-5% annual churn.\n\n## 8. MVP Roadmap\n\n| Milestone | Timeline | Deliverables |\n|-----------|----------|--------------|\n| M1 | Weeks 1\xe2\x80\x934 | Book import (CSV), renewal date extraction, pipeline view, pre-configured 90-day email sequences |\n| M2 | Weeks 5\xe2\x80\x938 | SMS reminders, daily priority queue, referral attribution logging, annual review scheduler |\n| M3 | Weeks 9\xe2\x80\x9312 | Automated referral thank-you, cross-sell scanner, communication log, carrier-specific templates |\n| M4 | Weeks 13\xe2\x80\x9316 | Team/multi-producer features, Stripe billing, self-serve onboarding, API for AMS integration |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M12 Target |\n|-----|-----------|------------|\n| Active agent subscriptions | 60 | 450 |\n| Time to first automated sequence | <6 hrs | <4 hrs |\n| Policy lapse prevention rate (agent-reported) | +8 ppts | +11 ppts |\n| MRR | $7,200 | $67,500 |\n| Monthly churn | <7% | <4% |\n| Referral tracking adoption | \xe2\x80\x94 | >60% of agents |\n| NPS | >48 | >65 |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|------|------------|--------|------------|\n| CSV import quality is too poor to auto-parse | High | High | Build robust field-mapping UI with preview; offer manual entry as always-on fallback |\n| Agents over-rely on sequences, under-personalize | Medium | Medium | Sequences send \xe2\x80\x9cfrom agent\xe2\x80\x9d with agent\xe2\x80\x99s name; encourage custom templates; approval mode shows agent each message before send |\n| TCPA violations (automated SMS without consent) | Medium | High | Require explicit opt-in checkbox during client import; hold SMS until consent confirmed |\n| Competing on price with AgencyZoom | Medium | High | Compete on setup simplicity; target agents who tried AgencyZoom and found it too complex |\n| Retention drops after initial renewal season | Medium | Medium | Add cross-sell and referral features that provide year-round value beyond renewal season |\n| Carrier APIs unavailable for real-time sync | Low | Medium | CSV import covers 95% of use cases; position real-time sync as future premium feature |',
 E'[{"step": 1, "action": "Setup friction analysis", "rationale": "The #1 complaint about existing tools (HubSpot, AgencyZoom) is setup time. Designed pre-configured insurance sequences to differentiate on time-to-value: import book, sequences start automatically."}, {"step": 2, "action": "90-day window research", "rationale": "Analyzed carrier cancellation notice requirements: most require 30-day notice. But agent interviews show clients who are first contacted at 90 days are 2.3x more likely to renew vs. 30 days."}, {"step": 3, "action": "Referral attribution feature scoping", "rationale": "Added referral tracking as a P0 because it creates a retention moat: agents who can see their referral ROI in the tool are extremely unlikely to churn from it."}, {"step": 4, "action": "TCPA compliance design", "rationale": "Automated SMS to insurance clients requires explicit consent under TCPA. Built consent collection into the import flow as a required step to avoid liability."}, {"step": 5, "action": "Competitive positioning", "rationale": "AgencyZoom targets agency operations managers. RenewalRadar targets individual agents who want something that just works. Different buyer, different UX philosophy."}, {"step": 6, "action": "Sequence approval mode", "rationale": "Added an optional \x27approve before send\x27 mode for agents who want control. Default is auto-send to reduce friction for the majority who want zero-touch automation."}]',
 'submitted', 29,
 NOW() - INTERVAL '8 days', NOW() - INTERVAL '8 days', NOW() - INTERVAL '8 days');

