INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(14, 20, E'# ClientKeeper \x2014 Relationship-First Insurance Client Management\n\n## 1. Executive Summary\n\nClientKeeper is a relationship management tool built around the philosophy that insurance clients are retained by relationships, not reminders. Where most tools focus on automated outreach, ClientKeeper adds a relationship quality layer: each client has a relationship score based on recency of meaningful contact, life event awareness, and referral history. Agents receive a weekly relationship health report that flags which clients are at risk of being poached by a competitor (score declining), which are ripe for a check-in conversation, and which should be asked for a referral. ClientKeeper automates the administrative tasks (renewal reminders, scheduled emails) while keeping the agent\xe2\x80\x99s attention on the high-value human moments.\n\n**Core Insight**: The best-retained clients feel known, not managed. ClientKeeper helps agents be present at life moments, not just renewal moments.\n\n**Year-1 Goals**:\n- 400 active subscriptions\n- Avg client retention improvement: +10 percentage points\n- MRR of $60,000 by month 12\n\n## 2. Market Analysis\n\n| Metric | Data | Source |\n|--------|------|--------|\n| Independent insurance agents (US) | ~360,000 | IIABA 2023 |\n| Target segment (200\xe2\x80\x93500 clients) | ~108,000 | Estimated |\n| Avg client lifetime value (P&C) | $4,800\xe2\x80\x938,500 | 6\xe2\x80\x9312 year avg retention |\n| Clients lost to competitors in year 1 after poaching attempt | 34% | JD Power 2023 Insurance Study |\n| % of losses that were preceded by no contact for 6+ months | 67% | Agent post-loss survey |\n| Cost to replace a lost client (prospecting + onboarding) | $400\xe2\x80\x93$900 | Estimated |\n| Agents who track client life events systematically | <12% | Proprietary survey |\n| TAM | ~$648M/year | 108,000 \xd7 $500/yr |\n| Year-1 SOM | ~$720K | 400 \xd7 $150/mo |\n\n## 3. Competitive Landscape\n\n| Product | Relationship Score | Life Event Tracking | Renewal Automation | At-Risk Alerts | Price/mo |\n|---------|-------------------|--------------------|--------------------|----------------|----------|\n| AgencyZoom | No | No | Yes | No | $99\xe2\x80\x93$249 |\n| Salesforce FSC | Partial | Partial | No | No | $225\xe2\x80\x93$300 |\n| HubSpot | No | No | Sequences only | No | $50\xe2\x80\x93$450 |\n| NowCerts | No | No | Basic | No | $79\xe2\x80\x93$159 |\n| HawkSoft | No | No | Basic | No | $200\xe2\x80\x93$400 |\n| **ClientKeeper** | **Yes (core)** | **Yes** | **Yes** | **Yes** | **$109\xe2\x80\x93$169** |\n\n## 4. Target User Personas\n\n### Persona A: Relationship-Focused Veteran Agent \xe2\x80\x94 Sandra Kowalczyk\n- **Age**: 54, independent agent in Wisconsin, 420 clients, 22 years in business\n- **Approach**: Built her book on personal relationships; clients know her personally\n- **Pain Points**:\n  1. Her book has grown to the point where she can\xe2\x80\x99t remember every client\xe2\x80\x99s situation intuitively\n  2. A competitor poached 6 clients last year during renewal season; she didn\xe2\x80\x99t realize they were at risk\n  3. Wants to maintain her personal touch at scale, but doesn\xe2\x80\x99t want to send robotic automated emails\n- **Goal**: A tool that helps her be personal at scale; surfaces who needs attention before she loses them\n- **WTP**: $139\xe2\x80\x93$169/month; her business is built on relationships\n\n### Persona B: Life Event-Aware Agent \xe2\x80\x94 James Thornton\n- **Age**: 42, independent life + home agent in Virginia, 280 clients\n- **Pain Points**:\n  1. He knows life events (new baby, new home, retirement) trigger insurance needs, but he finds out about them weeks or months later\n  2. His follow-up after life events is reactive, not proactive\n  3. Misses cross-sell moments because he\xe2\x80\x99s not tracking client life changes\n- **Goal**: Be the first call when a client has a life event, not the last\n- **WTP**: $109\xe2\x80\x93$139/month\n\n### Persona C: Analytics-Motivated Agent \xe2\x80\x94 Rachel Patel\n- **Age**: 35, independent multi-line agent in New Jersey, 195 clients, 5 years independent\n- **Pain Points**:\n  1. Wants data on her client relationships but current tools offer no analytics\n  2. Doesn\xe2\x80\x99t know which clients are at risk; makes guesses based on gut feel\n  3. Needs to see her full relationship health at a glance to prioritize her week\n- **Goal**: Relationship analytics that guide her weekly priorities\n- **WTP**: $99\xe2\x80\x93$119/month\n\n## 5. Core Features\n\n| Feature | Priority | Description |\n|---------|----------|-------------|\n| Relationship score per client (0\xe2\x80\x93100) | P0 | Calculated from: days since last contact, life event awareness, referral history, renewal history |\n| At-risk client alerts | P0 | Flag clients with score dropping >15 pts in 30 days or score <35 |\n| Weekly relationship health report | P0 | Top 5 at-risk, top 5 due for check-in, top 3 referral candidates |\n| Renewal reminder sequences (90/60/30/14 day) | P0 | Pre-configured multi-touch email + call prompt sequences |\n| Life event log | P0 | Agent notes life events (new baby, home purchase, divorce, retirement); triggers check-in prompt |\n| Annual check-in scheduling | P1 | Per-client annual review scheduled 12 months from last review |\n| Referral tracking + top-referrer leaderboard | P1 | Log referral source; identify top 10 referrers; trigger thank-you |\n| Meaningful contact log | P1 | Log each touchpoint; system distinguishes \xe2\x80\x9cmeaningful\xe2\x80\x9d (called, met in person) vs. \xe2\x80\x9cautomated\xe2\x80\x9d (email sent) |\n| Client book import (CSV) | P1 | Import from carrier exports; extract renewal dates, policy type, contact info |\n| Birthday + policy anniversary reminders | P2 | Personal touch outreach prompts (not automated\xe2\x80\x94agent reviews before sending) |\n\n## 6. Technical Architecture\n\n**Backend**: Go 1.22 + Echo v4. PostgreSQL 16.\n\n**Relationship Score Algorithm**: Weighted composite score recalculated nightly per client:\n- Days since last meaningful contact (40% weight)\n- Life event freshness (20% weight: higher score if recent event logged)\n- Referral history (20% weight: referrals given/received)\n- Renewal consistency (20% weight: consecutive on-time renewals)\n\nScore stored in client record; historical scores stored for trend analysis (weekly snapshots).\n\n**Alert Engine**: Nightly job compares current score to 30-day rolling average. Clients with >15-point drop queued for at-risk alert. Digest email to agent at 7 AM each morning.\n\n**Communications**: SendGrid for agent-to-client emails (agent\xe2\x80\x99s SMTP relay). Twilio for SMS. All automated messages flagged as automated in the contact log; agent can always send manual messages from the client view.\n\n**Frontend**: Next.js 15. Client list view sorted by relationship score by default (lowest scores first). Score trend sparkline per client. Weekly report is a separate email digest with 3-section layout.\n\n**Privacy**: Client contact info encrypted at rest. Score algorithm is transparent (agent can see exact breakdown per client). No client data shared between agents.\n\n## 7. Business Model\n\n| Plan | Price/Month | Clients | Features |\n|------|-------------|---------|----------|\n| Essential | $109 | Up to 250 | Relationship scoring, at-risk alerts, weekly report, renewal sequences |\n| Professional | $149 | Up to 500 | + Life event tracking, referral system, annual check-ins, communication log |\n| Team | $229 | Unlimited | + Multi-producer view, agency health report, shared client access |\n\n**Positioning note**: Price slightly above NowCerts ($79\xe2\x80\x93$159) and below AgencyZoom ($99\xe2\x80\x93$249) while offering the unique relationship score feature that neither provides.\n\n## 8. MVP Roadmap\n\n| Milestone | Timeline | Deliverables |\n|-----------|----------|--------------|\n| M1 | Weeks 1\xe2\x80\x934 | Client + policy import, renewal sequences, basic contact log, relationship score v1 (contact recency only) |\n| M2 | Weeks 5\xe2\x80\x938 | Full relationship score (all 4 factors), at-risk alerts, weekly health report, life event logging |\n| M3 | Weeks 9\xe2\x80\x9312 | Referral tracking, annual check-in scheduler, meaningful vs. automated contact distinction |\n| M4 | Weeks 13\xe2\x80\x9316 | Birthday/anniversary reminders, team features, Stripe billing, self-serve onboarding |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M12 Target |\n|-----|-----------|------------|\n| Active subscriptions | 52 | 400 |\n| Avg relationship score improvement (enrolled agents) | +8 pts | +18 pts |\n| At-risk alert action rate (agent took action within 7 days) | >55% | >70% |\n| MRR | $6,200 | $60,000 |\n| Monthly churn | <7% | <4% |\n| Weekly health report open rate | >65% | >72% |\n| NPS | >52 | >70 |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|------|------------|--------|------------|\n| Relationship score feels arbitrary or unfair to agents | Medium | High | Make score fully transparent (show exact factor breakdown); allow agent to override score for any client |\n| Life event tracking requires agent discipline (manual entry) | High | Medium | Make logging a life event frictionless (one tap from client view); remind in weekly report if no events logged in 60 days |\n| Score manipulation (agent logs fake contacts to boost score) | Medium | Low | Distinguish meaningful vs. automated contacts; manual logs are weighted lower than verified outbound calls |\n| Agents prefer automated-everything over relationship focus | Medium | Medium | Offer both: automation handles reminders; relationship layer handles prioritization. Not either/or. |\n| AgencyZoom or NowCerts adds relationship scoring | Low | High | Patent application on scoring algorithm; build 12+ months of client score history as switching cost |\n| SMB insurance SaaS market consolidation | Low | Medium | Build integration-friendly API; position as best-of-breed layer on top of any AMS system |',
 E'[{"step": 1, "action": "Core differentiation definition", "rationale": "Observed that all existing tools focus on task automation. Decided to differentiate on relationship intelligence: not just \x27did we send a reminder\x27 but \x27is this relationship healthy\x27."}, {"step": 2, "action": "Relationship score algorithm design", "rationale": "Chose 4 factors (recency, life events, referrals, renewal consistency) as measurable proxies for relationship quality. Tested weights with 10 agents who reviewed their own books."}, {"step": 3, "action": "At-risk alert threshold calibration", "rationale": "Set the 15-point drop trigger based on agent feedback: a sudden drop in score is more meaningful than an absolute low score. A client who was always cold is fine; a client who was warm and went cold is at risk."}, {"step": 4, "action": "Meaningful vs. automated contact distinction", "rationale": "Key design decision: automated emails should NOT count the same as a real phone call in the relationship score. Agents agreed strongly. This prevents gaming and keeps the score meaningful."}, {"step": 5, "action": "Pricing position", "rationale": "Positioned above NowCerts (commodity automation) and below AgencyZoom (agency operations). The unique relationship score feature justifies the premium."}, {"step": 6, "action": "Privacy and transparency design", "rationale": "Agents were concerned about a \x27black box\x27 score. Made score breakdown fully visible per client; added agent override capability to maintain trust in the system."}]',
 'submitted', 22,
 NOW() - INTERVAL '5 days', NOW() - INTERVAL '5 days', NOW() - INTERVAL '5 days');

