INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(15, 16, E'# RenewalDesk \x2014 Proactive Engagement Renewal for Small CPA Practices\n\n## 1. Executive Summary\n\nRenewalDesk is a focused engagement renewal tool that solves one problem exceptionally well: ensuring that every client of a small accounting firm has a current, signed engagement letter before work begins. It combines automated expiration tracking, one-click renewal letter generation (pre-populated from the prior year\xe2\x80\x99s engagement terms), e-signature delivery, and a capacity planning calendar that visualizes the renewal workload across the year. For small CPA firms, a lapsed engagement letter is both a liability risk and a revenue risk\xe2\x80\x94RenewalDesk eliminates both by making renewal as easy as clicking \xe2\x80\x9cRenew All for Q1.\xe2\x80\x9d\n\n**Core Insight**: The hardest part of engagement renewal is not sending the email\xe2\x80\x94it\xe2\x80\x99s generating an updated letter, routing it for signatures, and tracking who has and hasn\xe2\x80\x99t returned it. RenewalDesk automates all three steps.\n\n**Year-1 Goals**:\n- 280 firm subscriptions\n- Avg engagement renewal cycle time reduced from 3\xe2\x80\x934 weeks to <1 week\n- MRR of $42,000 by month 12\n\n## 2. Market Analysis\n\n| Metric | Data | Source |\n|--------|------|--------|\n| CPA firms with 2\xe2\x80\x9310 staff | ~44,000 | AICPA 2023 |\n| Firms with 50\xe2\x80\x93150 business clients | ~18,000 | Estimated |\n| Avg engagement letter renewal cycle time | 18\xe2\x80\x9328 days | Firm interviews |\n| % of firms that begin work without signed renewal | 31% | CAMICO malpractice data |\n| Avg malpractice claim related to engagement scope | $45,000 | CAMICO 2022 |\n| Firms with automated engagement renewal process | <15% | CPA Practice Advisor survey |\n| Time spent per client on renewal admin | 45\xe2\x80\x9390 min | Firm administrator interview |\n| TAM | ~$270M/year | 18,000 \xd7 $1,250/yr |\n| Year-1 SOM | ~$504K | 280 \xd7 $150/mo |\n\n## 3. Competitive Landscape\n\n| Product | Engagement Letter Generation | E-Signature | Renewal Tracking | Capacity Planning | Price/mo |\n|---------|------------------------------|-------------|------------------|-------------------|----------|\n| TaxDome | Template-based | Yes | No | No | $50/user |\n| Canopy | Manual | Yes (add-on) | Basic | No | $50\xe2\x80\x9375/user |\n| Karbon | No | No | No | Partial | $59\xe2\x80\x9389/user |\n| PandaDoc | Yes (generic) | Yes | Basic | No | $35\xe2\x80\x9365/user |\n| DocuSign + Sheets | No (manual) | Yes | No (manual) | No | $25/user + effort |\n| **RenewalDesk** | **Yes (pre-populated)** | **Yes** | **Yes (core)** | **Yes** | **$109\xe2\x80\x93$159** |\n\n## 4. Target User Personas\n\n### Persona A: Risk-Conscious Managing Partner \xe2\x80\x94 Frank DiNapoli\n- **Age**: 56, managing partner of a 5-person CPA firm in New York, 120 clients\n- **Background**: Attended an AICPA risk management seminar; knows that working without a signed engagement letter creates malpractice exposure\n- **Pain Points**:\n  1. Two staff members generate engagement letters; they use slightly different templates and neither tracks whether clients returned them signed\n  2. He learned about a lapsed engagement when a client disputed the scope of a bookkeeping engagement\n  3. Renewal season (October\xe2\x80\x93December for calendar-year clients) is chaos\n- **Goal**: Every client has a current signed engagement letter before January 1; he can prove it\n- **WTP**: $149\xe2\x80\x93$159/month; compares it to the cost of one malpractice claim deductible\n\n### Persona B: Firm Administrator \xe2\x80\x94 Janet Wysocki\n- **Age**: 49, office manager at a 3-partner CPA firm in Michigan, 95 clients\n- **Pain Points**:\n  1. Generates engagement letters one at a time using a Word template; copy-paste errors happen\n  2. Tracks signature status in a spreadsheet that partners don\xe2\x80\x99t update consistently\n  3. Chasing clients for signed letters is the most time-consuming part of her job each fall\n- **Goal**: Generate all renewal letters in bulk, send for e-signature, and track who has signed without any spreadsheet\n- **WTP**: N/A (firm pays; she\xe2\x80\x99s the power user)\n\n### Persona C: Boutique Tax CPA \xe2\x80\x94 Claire Fontaine\n- **Age**: 42, solo CPA with 62 business clients, growing\n- **Pain Points**:\n  1. Sends engagement letters via email PDF; clients print, sign, scan, return. 30% don\xe2\x80\x99t bother.\n  2. Has no visibility into who has outstanding unsigned letters until she starts work and checks\n  3. Wants a professional renewal process that matches her client expectations\n- **WTP**: $109\xe2\x80\x93$119/month\n\n## 5. Core Features\n\n| Feature | Priority | Description |\n|---------|----------|-------------|\n| Engagement record (client, type, value, dates) | P0 | Per-client engagement with expiration tracking |\n| Pre-populated renewal letter generation | P0 | Auto-fill updated letter from prior year terms; firm reviews before sending |\n| E-signature send + tracking | P0 | Send for signature via email; track viewed/signed/declined per client |\n| Renewal status dashboard | P0 | Table view: all clients \xd7 renewal status \xd7 days until expiry |\n| Automated reminder to unsigned clients | P0 | Auto-resend if not signed in 7 days; escalation after 14 days |\n| Bulk renewal action | P1 | Select all clients expiring in a date range; generate + send all letters in one action |\n| Capacity planning calendar | P1 | Show number of renewals due each month; flag months exceeding firm capacity threshold |\n| Engagement letter template library | P1 | Multiple templates by engagement type (tax, bookkeeping, advisory, audit); firm-customizable |\n| Signed document archive | P1 | All signed letters stored with audit trail; searchable by client and year |\n| Partner/staff assignment per engagement | P2 | Route renewal review to responsible partner before send |\n\n## 6. Technical Architecture\n\n**Backend**: Go 1.22 + Echo v4. PostgreSQL 16. S3 for document storage.\n\n**Letter Generation Engine**: Template system using Handlebars-style merge fields. Templates stored as HTML; rendered server-side to PDF (Puppeteer headless Chrome via Docker sidecar). Pre-populated fields: client name, engagement type, prior year fee, current year fee, service list from prior engagement, effective dates.\n\n**E-Signature**: Dropbox Sign (HelloSign) embedded API. Webhook handler updates engagement status in real time on signing events (viewed, signed, declined). Signed PDF automatically stored to S3 archive.\n\n**Bulk Renewal Engine**: Async job queue (Redis + worker). Firm selects cohort (e.g., \xe2\x80\x9call clients expiring in Q1 2026\xe2\x80\x9d). Worker generates PDFs in parallel; sends signature requests; updates status. Progress bar in UI. Estimated <8 seconds per 100 clients.\n\n**Capacity Calendar**: Aggregates engagement expiry dates by month. Configurable firm capacity limit (e.g., \xe2\x80\x9cwe can process 30 renewals per month\xe2\x80\x9d). Calendar highlights overloaded months in yellow/red.\n\n**Frontend**: Next.js 15 + TailwindCSS 4. Primary views: renewal status table (primary daily driver), capacity calendar, client engagement history.\n\n## 7. Business Model\n\n| Plan | Price/Month | Clients | Team | Features |\n|------|-------------|---------|------|----------|\n| Solo | $109 | Up to 80 | 1 | Engagement tracking, e-signature, renewal reminders, document archive |\n| Firm | $149 | Up to 150 | Up to 6 | + Bulk renewal, capacity calendar, template library, partner assignment |\n| Multi-Partner | $219 | Unlimited | Unlimited | + Analytics, QBO/Xero sync, API, priority support |\n\n**E-signature volume**: 100 signatures/month included. $0.40 per additional signature (Dropbox Sign pass-through + margin).\n\n## 8. MVP Roadmap\n\n| Milestone | Timeline | Deliverables |\n|-----------|----------|--------------|\n| M1 | Weeks 1\xe2\x80\x934 | Engagement records, expiry tracking, renewal status dashboard, manual letter upload + e-signature (Dropbox Sign) |\n| M2 | Weeks 5\xe2\x80\x938 | Pre-populated letter generation (PDF), automated unsigned-client reminders, signed document archive |\n| M3 | Weeks 9\xe2\x80\x9312 | Bulk renewal engine, capacity planning calendar, template library, partner assignment |\n| M4 | Weeks 13\xe2\x80\x9316 | Renewal analytics, QuickBooks/Xero client sync, Stripe billing, self-serve onboarding |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M12 Target |\n|-----|-----------|------------|\n| Active firm subscriptions | 38 | 280 |\n| Avg renewal cycle time | <10 days | <7 days |\n| Engagement lapse rate (enrolled firms) | <1% | <0.5% |\n| MRR | $4,200 | $42,000 |\n| Monthly churn | <5% | <3% |\n| Bulk renewal adoption rate | \xe2\x80\x94 | >55% of Firm plan |\n| NPS | >58 | >72 |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|------|------------|--------|------------|\n| PDF generation inconsistencies (formatting errors) | Medium | High | Extensive template QA; allow firm to preview every letter before send; offer \xe2\x80\x9csend one test letter\xe2\x80\x9d during onboarding |\n| Clients don\xe2\x80\x99t use e-signature (prefer paper) | Medium | Medium | Always offer PDF download + manual upload option; e-signature is the recommended path but not mandatory |\n| Dropbox Sign pricing increases | Low | Medium | Abstract behind e-signature adapter; can switch to DocuSign, PandaDoc, or Adobe Sign |\n| CPA firms start renewal too late (November for January expiry) | High | Medium | Design GTM for September onboarding; send \xe2\x80\x9cstart before tax season\xe2\x80\x9d messaging in August |\n| Template customization requires too much setup | Medium | Medium | Ship 8 pre-built AICPA-style templates for common engagement types; most firms can use as-is |\n| AICPA sample engagement letter changes create compatibility issues | Low | Low | Templates are firm-customizable; flag when AICPA publishes updated samples and prompt firm to review |',
 E'[{"step": 1, "action": "Malpractice risk framing", "rationale": "CAMICO data shows 31% of CPA firms start work without a signed renewal. Average malpractice claim related to engagement scope is $45K. This makes a $149/mo tool a risk management purchase, not just an efficiency tool."}, {"step": 2, "action": "Renewal letter generation as core feature", "rationale": "Interviews revealed the bottleneck is not sending a reminder; it\xe2\x80\x99s generating an updated letter. Pre-populated renewal from prior year terms cuts letter creation from 30 min to 2 min."}, {"step": 3, "action": "Bulk renewal design", "rationale": "Most small firms have 40-80% of clients on calendar-year engagements, all expiring at once. Bulk renewal (generate + send all in one action) is the feature that separates RenewalDesk from manual processes."}, {"step": 4, "action": "E-signature vendor selection", "rationale": "Compared HelloSign, DocuSign, PandaDoc. HelloSign (Dropbox Sign) has the best embedded signing UX and most competitive per-signature cost at SMB volumes. Abstracted behind adapter."}, {"step": 5, "action": "Capacity calendar feature", "rationale": "Accounting firms don\xe2\x80\x99t just need renewal reminders; they need to know if they\xe2\x80\x99ve created a workload problem. The capacity calendar helps firms stagger renewals before Q4 becomes unmanageable."}, {"step": 6, "action": "GTM timing strategy", "rationale": "Best onboarding window is August-September when partners are planning Q4 but not yet overwhelmed. Designed all marketing around this window with \x27be ready for renewal season\x27 messaging."}]',
 'submitted', 43,
 NOW() - INTERVAL '10 days', NOW() - INTERVAL '10 days', NOW() - INTERVAL '10 days');

