INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(15, 23, E'# ScopeGuard \x2014 Engagement Scope & Contract Intelligence for CPA Firms\n\n## 1. Executive Summary\n\nScopeGuard is a contract and scope management platform for small CPA firms that goes beyond renewal reminders. It tracks not just when engagement letters expire, but whether the work being done matches the scope that was agreed upon. Scope creep is the silent revenue leak in accounting firms: partners add services informally, clients expect them to continue, and the engagement letter never gets updated. ScopeGuard surfaces scope mismatches, prompts scope amendment conversations before they become disputes, and automates the renewal cycle so nothing slips. The result is a firm that enters each tax season with every engagement letter current, every scope mismatch flagged, and every client fee conversation handled proactively.\n\n**Differentiation**: ScopeGuard is the only engagement management tool that tracks scope alignment, not just contract dates. It prevents the two most common CPA engagement disputes: lapsed letters and undocumented scope changes.\n\n**Year-1 Goals**:\n- 300 firm subscriptions\n- Average scope amendment revenue recovery: $3,200/firm/year\n- MRR of $45,000 by month 12\n\n## 2. Market Analysis\n\n| Metric | Data | Source |\n|--------|------|--------|\n| Small CPA firms (2\xe2\x80\x9310 staff) | ~44,000 | AICPA 2023 |\n| Firms with 50\xe2\x80\x93150 business clients | ~18,000 | Estimated |\n| % of firms reporting scope creep as a revenue problem | 61% | AICPA Practice Management survey |\n| Avg unrealized revenue from informal scope additions | $4,200/firm/year | Proprietary survey N=85 |\n| % of engagement disputes arising from scope ambiguity | 47% | CAMICO malpractice report |\n| Firms using any scope change management process | <22% | Same survey |\n| Firms with dedicated engagement renewal automation | <18% | CPA Practice Advisor |\n| TAM | ~$270M/year | 18,000 \xd7 $1,250/yr |\n| Year-1 SOM | ~$540K | 300 \xd7 $150/mo |\n\n## 3. Competitive Landscape\n\n| Product | Contract Tracking | Scope Tracking | Amendment Workflow | E-Signature | Price/mo |\n|---------|------------------|---------------|--------------------|-------------|----------|\n| Karbon | No | No | No | No | $59\xe2\x80\x9389/user |\n| Canopy | Basic | No | No | Add-on | $50\xe2\x80\x9375/user |\n| TaxDome | No | No | No | Yes | $50/user |\n| PandaDoc | Yes (generic) | No | Partial | Yes | $35\xe2\x80\x9365/user |\n| Ironclad | Yes (enterprise) | No | Yes | Yes | $500+/mo |\n| **ScopeGuard** | **Yes** | **Yes (unique)** | **Yes** | **Yes** | **$119\xe2\x80\x93$179** |\n\n## 4. Target User Personas\n\n### Persona A: Partner Who Has Been Burned by Scope Disputes \xe2\x80\x94 Mark Griffith\n- **Age**: 48, managing partner of a 4-person CPA firm in Oregon, 88 clients\n- **Incident**: A 2-year bookkeeping client started requesting monthly management reports. His team delivered them for 8 months before a fee dispute revealed the engagement letter only covered quarterly reports.\n- **Pain Points**:\n  1. No process to document when informal service additions happen\n  2. Engagement letters go stale but no one flags the scope drift\n  3. Fee conversations are reactive and uncomfortable because there\xe2\x80\x99s no documentation\n- **Goal**: A tool that forces scope documentation and flags when work exceeds agreed scope\n- **WTP**: $149\xe2\x80\x93$169/month; frames as preventing one dispute per year\n\n### Persona B: Compliance-Focused Partner \xe2\x80\x94 Dr. Lisa Wentworth, CPA\n- **Age**: 53, 2-partner firm in Massachusetts, 102 clients, emphasis on risk management\n- **Background**: Serves on local AICPA chapter; knows malpractice implications well\n- **Pain Points**:\n  1. Wants documented scope for every client at all times, not just at engagement inception\n  2. Current process: engagement letter renewed annually but scope updated only when partner remembers\n  3. Needs audit-ready documentation of scope changes for potential E&O claims\n- **Goal**: Complete scope + contract history per client; audit trail of every change\n- **WTP**: $159\xe2\x80\x93$179/month for compliance-grade documentation\n\n### Persona C: Efficiency-Seeking Firm Administrator \xe2\x80\x94 Hector Ramirez\n- **Age**: 38, manages operations for a 7-person CPA firm in California, 130 clients\n- **Pain Points**:\n  1. Manages engagement renewals manually; 130 letters per year is a quarter-long project\n  2. Partners sometimes add services in client meetings without telling him\n  3. Cannot quickly answer \xe2\x80\x9cwhat services are we providing to Client X right now?\xe2\x80\x9d without digging through folders\n- **Goal**: Single source of truth for every client\xe2\x80\x99s current scope; renewal handled automatically\n- **WTP**: N/A (firm pays; he is primary champion)\n\n## 5. Core Features\n\n| Feature | Priority | Description |\n|---------|----------|-------------|\n| Engagement record with service scope list | P0 | Per-client: engagement letter, service line items, agreed fees, effective dates |\n| Contract expiration tracking + renewal sequences | P0 | Auto-reminders at 90/60/30/14 days; partner and client notifications |\n| Scope amendment log | P0 | Any change to agreed services creates a dated amendment record; requires approval |\n| Scope drift alert | P0 | Partner logs a service delivered outside agreed scope; system prompts amendment |\n| Amendment letter generation + e-signature | P1 | Auto-generate scope amendment letter from change log; route for signature |\n| Renewal letter generation (pre-populated) | P1 | Pull prior year terms; generate updated letter with fee and scope fields |\n| Bulk renewal workflow | P1 | Generate + send all renewals for a date range in one action |\n| Seasonal capacity dashboard | P1 | Renewal density by month; flag capacity constraints before they happen |\n| Audit trail export | P1 | Full history per client: all engagement letters, amendments, signing dates, scope changes |\n| QuickBooks client sync | P2 | Import client list from QBO to seed EngageTrack |\n\n## 6. Technical Architecture\n\n**Backend**: Go 1.22 + Echo v4. PostgreSQL 16 with JSONB for flexible scope line item storage (scope items are semi-structured: service name, fee, frequency, deliverable description).\n\n**Scope Model**: Engagement has a \xe2\x80\x9ccurrent scope snapshot\xe2\x80\x9d (JSONB array of service items) and a \xe2\x80\x9cscope amendment history\xe2\x80\x9d (append-only log). Each amendment: date, partner, reason, old scope, new scope, amendment letter reference, signature status.\n\n**Scope Drift Detection**: When a partner logs time or a service in the billing system and the service code is not in the current engagement scope, ScopeGuard raises a drift alert. (Integration-based in V2; manual logging in V1.)\n\n**Letter Generation**: Handlebars HTML templates \xe2\x80\x92 Puppeteer PDF. Scope items rendered as a table in the PDF. Amendment letters show \xe2\x80\x9cAdded Services\xe2\x80\x9d and \xe2\x80\x9cRemoved Services\xe2\x80\x9d in a change diff format.\n\n**E-Signature**: Dropbox Sign embedded API. Webhooks update engagement and amendment status in real time. All signed documents archived to S3 with per-client folder structure.\n\n**Frontend**: Next.js 15 + TailwindCSS 4. Client view: active scope summary (always current), amendment history timeline, renewal status. Partner view: scope drift alerts queue, upcoming renewals, seasonal calendar.\n\n## 7. Business Model\n\n| Plan | Price/Month | Clients | Team | Features |\n|------|-------------|---------|------|----------|\n| Essential | $119 | Up to 75 | 1\xe2\x80\x932 | Contract tracking, renewal sequences, scope log, e-signature |\n| Professional | $159 | Up to 150 | Up to 5 | + Amendment workflow, scope drift alerts, bulk renewal, capacity calendar |\n| Firm | $229 | Unlimited | Unlimited | + Audit trail export, QuickBooks sync, team analytics, API |\n\n**E-signature overage**: 100 signatures/month included in Professional+. $0.45/additional signature.\n\n## 8. MVP Roadmap\n\n| Milestone | Timeline | Deliverables |\n|-----------|----------|--------------|\n| M1 | Weeks 1\xe2\x80\x934 | Engagement records with scope items, expiry tracking, renewal email sequences, manual document upload + e-signature |\n| M2 | Weeks 5\xe2\x80\x938 | Scope amendment log, scope drift alert (manual trigger), amendment letter generation, renewal letter generation |\n| M3 | Weeks 9\xe2\x80\x9312 | Bulk renewal engine, seasonal capacity calendar, audit trail export, partner assignment |\n| M4 | Weeks 13\xe2\x80\x9316 | QuickBooks client sync, team analytics, Stripe billing, self-serve onboarding |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M12 Target |\n|-----|-----------|------------|\n| Active firm subscriptions | 40 | 300 |\n| Scope amendments logged per firm/year | 4.2 avg | 6.8 avg |\n| Revenue recovered from scope amendments (self-reported) | $1,800 avg | $3,200 avg |\n| MRR | $4,800 | $45,000 |\n| Monthly churn | <5% | <3% |\n| Engagement lapse rate | <0.5% | <0.2% |\n| NPS | >55 | >72 |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|------|------------|--------|------------|\n| Scope tracking requires partner discipline in logging | High | High | Make scope logging frictionless (quick-add service from predefined library); weekly email prompt if no scope activity in 30 days |\n| Partners resist documenting scope drift (uncomfortable client conversations) | Medium | High | Frame as protecting the partner: \xe2\x80\x9cDocumentation protects you if the client disputes the fee.\xe2\x80\x9d Train on how to present amendments positively. |\n| Scope JSONB model becomes complex for firms with many service types | Medium | Medium | Pre-ship 50 standard accounting service line items; firms add custom items only when needed |\n| PDF generation quality issues with complex scope tables | Medium | Medium | Extensive template testing; allow preview before send; manual PDF upload always available |\n| Dropbox Sign webhook reliability issues | Low | Medium | Implement webhook retry queue; fall back to polling API for signature status every 4 hours |\n| Karbon adds engagement letter tracking | Medium | High | Karbon is a workflow tool; CPA firms treat engagement management as separate from workflow. Maintain independence from workflow tools; integrate via API instead of competing. |',
 E'[{"step": 1, "action": "Scope creep insight", "rationale": "Interviewed 15 CPA firm partners; 9 had a recent story of a scope dispute. The common pattern: work expanded informally, engagement letter never updated, fee conversation became adversarial."}, {"step": 2, "action": "Differentiation via scope tracking", "rationale": "All competitors track contract dates. None track whether work matches the agreed scope. Scope tracking is the unique value proposition and the harder technical problem."}, {"step": 3, "action": "JSONB scope model design", "rationale": "Service scope items are semi-structured (vary by firm and engagement type). JSONB with a schema validator gives flexibility to accommodate different firm templates without a rigid relational schema."}, {"step": 4, "action": "Amendment workflow design", "rationale": "Scope amendments are sensitive (they mean asking a client to pay more). Designed the amendment letter to show \x27added services\x27 and \x27removed services\x27 clearly so the client immediately understands the change."}, {"step": 5, "action": "Positioning vs. competitors", "rationale": "Karbon targets workflow management at $59-89/user. Canopy targets full practice management. ScopeGuard is narrower: engagement lifecycle only, at firm-level pricing (not per-user). More accessible for small firms."}, {"step": 6, "action": "Revenue recovery metric design", "rationale": "Chose \x27scope amendment revenue recovered\x27 as the primary business outcome metric because it translates directly to ROI. A firm that recovers $3,200/year from scope amendments is paying $1,790/year for ScopeGuard. Clear positive ROI."}]',
 'submitted', 36,
 NOW() - INTERVAL '7 days', NOW() - INTERVAL '7 days', NOW() - INTERVAL '7 days');
